+fn resolve_segment_block_number(segments: &[JournalSegment], index: u64) -> Option<BlockNumber> {
+    let mut base = 0_u64;
+    for segment in segments {
+        let end = base.checked_add(segment.blocks)?;
+        if index < end {
+            return segment.resolve(index - base);
+        }
+        base = end;
+    }
+    None
+}
