+fn trim_trailing_zero_blocks(bytes: &mut Vec<u8>, block_len: usize) {
+    while bytes.len() >= block_len
+        && bytes[bytes.len() - block_len..]
+            .iter()
+            .all(|byte| *byte == 0)
+    {
+        bytes.truncate(bytes.len() - block_len);
+    }
+}
