+        &self,
+        cx: &Cx,
+    ) -> Result<Option<Ext4FastCommitReplayEvidence>, FfsError> {
+        let (block_size, journal_inum, journal_dev) = match self.ext4_superblock() {
+            Some(sb) => (sb.block_size, sb.journal_inum, sb.journal_dev),
+            None => return Ok(None),
+        };
