+        let replay = replay_fast_commit(&fc_bytes)?;
+        let evidence = Ext4FastCommitReplayEvidence {
+            reserved_fc_blocks: journal_sb.num_fc_blocks,
+            bytes_collected: u64::try_from(fc_bytes.len()).unwrap_or(u64::MAX),
+            replay,
+        };
